import{_ as t,o,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"82. Enrolled Nurses Classification","description":"","frontmatter":{"title":"82. Enrolled Nurses Classification","eba":"Nurses and Midwives 2024-2028","topics":["classifications"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/82-enrolled-nurses-classification.md","filePath":"ebas/nurses-midwives/classification-staffing/82-enrolled-nurses-classification.md"}'),r={name:"ebas/nurses-midwives/classification-staffing/82-enrolled-nurses-classification.md"};function s(a,e,p,l,c,d){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_82-enrolled-nurses-classification" tabindex="-1">82. Enrolled Nurses Classification <a class="header-anchor" href="#_82-enrolled-nurses-classification" aria-label="Permalink to &quot;82. Enrolled Nurses Classification&quot;">​</a></h1><p>Part 1 – Scope</p><p><strong>82.1</strong> Scope</p><p>This clause 82 is split into 5 parts:</p><p><strong>(a)</strong> Part 1 (clause 82.1 - 82.2) explains the scope of this clause and the applicable definitions;</p><p><strong>(b)</strong> Part 2 (clauses 82.3 - 82.6) sets out the classifications and classification descriptors for Enrolled Nurses;</p><p><strong>(c)</strong> Part 3 (clause 82.7) sets out the translation arrangements for Enrolled Nurses employed as at 31 March 2012;</p><p><strong>(d)</strong> Part 4 (clauses 82.10 - 82.14) describes the recruitment and appointment process for Enrolled Nurses; and</p><p><strong>(e)</strong> Part 5 (clauses 82.15 - 82.18) sets out the process for Enrolled Nurses to advance to EN3, including the advancement criteria and competency standards.</p><p><strong>82.2</strong> Definitions</p><p><strong>(a)</strong> Enrolled Nurse has the meaning provided by <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4</a> (Definitions).</p><p><strong>(b)</strong> A Year of Experience has the meaning provided by <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4</a> (Definitions).</p><p>Part 2 – Classifications for Enrolled Nurses</p><p><strong>82.3</strong> Enrolled Nurse Level 1 (EN1)</p><p><strong>(a)</strong> EN1 applies to Enrolled Nurses who do not hold an NMBA approved qualification in administration of medicines.</p><p><strong>(b)</strong> This level also applies to nurses formerly known as Mothercraft Nurses who are registered with the NMBA as ENs with notation, and to those who, while not registered as nurses, perform similar work with comparable underpinning education. Such nurses will be paid at the nearest (higher) pay point in the EN1 range to their current Mothercraft Nurse rate of pay, unless they are already paid above the maximum EN1 rate of pay, in which case they will retain their current rate of pay, adjusted only by annual pay increases applying under this Agreement.</p><p><strong>(c)</strong> Progression – An EN1 will progress through the increments on completion of a year of experience, including previous experience.</p><p><strong>(d)</strong> There is no automatic progression for an EN1 with a medication administration notation to the EN2 classification.</p><p><strong>82.4</strong> Enrolled Nurse Level 2 (EN2)</p><p><strong>(a)</strong> Cert IV Entry – EN Level 2.1 is the entry to practise rate for the first year of experience of an Enrolled Nurse who holds a NMBA approved Cert IV – Nursing [HLT 43407] qualification without prior experience as an Enrolled Nurse. On</p><p>completion of each year of experience thereafter the Employee will progress to the next increment up to and including EN Level 2.6.</p><p><strong>(b)</strong> EN 2.1 to 2.6 inclusive will also apply to an Enrolled Nurse who holds a NMBA approved qualification in administration of medicines with an Administration of Medication Scope of up to four routes. Experience includes experience as an Enrolled Nurse prior to holding the Administration of Medication qualification.</p><p><strong>(c)</strong> Diploma Entry – EN Level 2.3 is the entry to practise rate for the first year of experience of an Enrolled Nurse who holds a NMBA approved Diploma of Nursing [HLT 51607] qualification without prior experience as an Enrolled Nurse. On completion of each year of experience thereafter the Employee will progress to the next increment up to and including EN 2.7.</p><p><strong>(d)</strong> EN 2.3 to 2.7 inclusive also apply to an Enrolled Nurse who holds a NMBA approved qualification in administration of medicines with an Administration of Medication Scope of all five routes. Experience includes experience as an Enrolled Nurse prior to holding the Administration of Medication qualification.</p><p><strong>(e)</strong> Progression – An EN2 will progress through the increments on completion of a year of experience, including previous experience.</p><p><strong>(f)</strong> There is no automatic progression for an EN2 to the EN3 classification.</p><p><strong>82.5</strong> Enrolled Nurse Level 3 (EN3)</p><p><strong>(a)</strong> EN3.1 applies to an Enrolled Nurse who does not hold a NMBA approved qualification in administration of medicines but who meets the criteria in clause 82.15.</p><p><strong>(b)</strong> EN3.2 applies to an Enrolled Nurse with an Administration of Medication Scope of up to four routes and who meets the criteria in clause 82.15.</p><p><strong>(c)</strong> EN3.3 applies to an Enrolled Nurse who holds a NMBA approved qualification in administration of medicines with an Administration of Medication Scope of up to five routes and who meets the criteria in clause 82.15.</p><p><strong>(d)</strong> From 1 September 2024, an Enrolled Nurse working in aged care who has responsibility for supervising other Employees will be classified at EN3 in accordance with clause 82.5, provided that clause 82.15 does not apply unless the Enrolled Nurse was already an EN3 as at 17 May 2024, or meets the criteria at clause 82.16.</p><p><strong>82.6</strong> Enrolled Nurse Level 3 (savings provisions)</p><p><strong>(a)</strong> EN3.1 applies to an Enrolled Nurse who does not hold a NMBA approved qualification in administration of medicines and, as at 31 March 2012, was in receipt of the Senior Allowance.</p><p><strong>(b)</strong> EN3.2 applies to an Enrolled Nurse who holds a NMBA approved qualification of medicines with an Administration of Medication Scope of up to four routes and, as at 31 March 2012, was in receipt of the Senior Allowance.</p><p><strong>(c)</strong> EN3.3 applies to an Enrolled Nurse who holds a NMBA approved qualification of medicines with an Administration of Medication Scope of up to five routes and, as at 31 March 2012, was in receipt of the Senior Allowance.</p><p>Part 3 – Translation Arrangements</p><p><strong>82.7</strong> The translation arrangements in clause 82.4 of the 2016 Agreement continue to apply to Enrolled Nurses employed as at 31 March 2012.</p><p><strong>82.8</strong> Prior to 31 August 2024, each Employer will ensure that an EN with supervisory responsibility, who is not classified at EN3, is notified in writing of whether the Employer:</p><p><strong>(a)</strong> expects that supervisory responsibility to continue beyond 1 September 2024; and</p><p><strong>(b)</strong> if the Employer does not expect that supervisory responsibility to continue beyond 1 September 2024, the alternate supervisory arrangements to occur from 1 September 2024.</p><p><strong>82.9</strong> A dispute about the existence, or continuation, of supervisory responsibilities, or alternate supervisory arrangements, will be referred to the WIC in the first instance.</p><p>Part 4 – Recruitment and appointment to EN (new or vacant positions)</p><p><strong>82.10</strong> An Employer may advertise an EN vacancy as an EN1, EN2 or EN3 position, dependent upon the role.</p><p><strong>82.11</strong> A position will be advertised at EN3 where the work to be performed by the successful applicant is intended to include four or more of the criteria in clause 82.16.</p><p><strong>82.12</strong> Appointment of an EN1 will only occur where the successful applicant does not hold a NMBA approved qualification in administration of medicines.</p><p><strong>82.13</strong> Appointment of an EN2 will be subject to the successful applicant having a NMBA approved qualification in administration of medicines. The successful applicant will be remunerated at the EN2 level consistent with the number of routes of their Administration of Medication Scope.</p><p><strong>82.14</strong> Appointment to EN3 position will apply where:</p><p><strong>(a)</strong> the successful applicant has applied for a position advertised as EN3;</p><p><strong>(b)</strong> a decision is made on interview to classify the applicant as EN3; or</p><p><strong>(c)</strong> the successful applicant provides acceptable evidence that they are an existing EN3. Acceptable evidence includes:</p><p><strong>(i)</strong> payslip;</p><p><strong>(ii)</strong> certificate of service; or</p><p><strong>(iii)</strong> letter of appointment.</p><p>Part 5 – Advancement to Enrolled Nurse Level 3</p><p><strong>82.15</strong> Enrolled Nurse Level 3 Advancement Criteria</p><p><strong>(a)</strong> To meet the advancement criteria, an Enrolled Nurse is to meet both (b)(i) and (b)(ii) below before making an application.</p><p><strong>(b)</strong> The eligibility criteria are:</p><p><strong>(i)</strong> can provide evidence of achievement of four out of the ten Advanced EN3 Competency Standards below; and</p><p><strong>(ii)</strong> either:</p><p><strong>(A)</strong> a minimum of four years post-registration experience as an Enrolled Nurse; or</p><p><strong>(B)</strong> a post-registration qualification (of at least 6 months or 200 hours duration), a component of which is relevant to the role.</p><p><strong>82.16</strong> Advanced Enrolled Nurse Level 3 Competency Standards:</p><p>The following are examples of competency standards that meet the criteria in subclause 82.15(b)(i) above.</p><p>Note: Employers, Employees, the VHIA and Unions recognise that additional opportunities may exist that are comparable in terms of skill or responsibility to those below. A lack of opportunity to meet sufficient standards is not to be used as a rationale for denying an Employee classification at EN3.</p><p><strong>(a)</strong> Contributes to the education of new graduate Enrolled Nurses and/or Trainee Enrolled Nurses. For example, the Advanced Enrolled Nurse may precept or mentor new graduate Enrolled Nurses, and/or Trainee Enrolled Nurses or contribute to the performance appraisal of less experienced Enrolled Nurses.</p><p><strong>(b)</strong> Is involved in committees and working parties within and/or beyond the work unit.</p><p><strong>(c)</strong> Assists in the coordination of delegated activities of other staff under the guidance and direction of the Registered Nurse or Registered Midwife. For example, guides and supports activities of other Enrolled Nurses.</p><p><strong>(d)</strong> Acts as a resource to others. For example, may take responsibility for a specific task, such as equipment maintenance schedules, budgets, rosters or stock control.</p><p><strong>(e)</strong> Contributes to quality improvement within their work area or the workplace and/or changes in enrolled nursing practice initiatives. For example, identifies risks and potential outcomes during assessments or identifies and implements harm minimisation strategies.</p><p><strong>(f)</strong> Practises using specialised or advanced knowledge and skills in a clinical area within the enrolled nursing scope of practice. For example, applies acquired knowledge in wound or continence management or dementia or child or family health care in the provision of care.</p><p><strong>(g)</strong> Modifies practice to accommodate patient/client health care needs of individuals and groups in different environments. For example, contributes to effective utilisation of nursing resources in the context of changing workloads or responds effectively to changes in clinical situations.</p><p><strong>(h)</strong> Undertakes an additional responsibility either individually or as part of a clinical / quality team e.g. resource nurse, occupational health and safety rep, no lift/back attack/smart moves/back off/-back 4 life portfolio, alcohol and other drugs portfolio, continence resource officer, ACFI officer, infection control, falls prevention, pressure ulcer prevention, mental health portfolio, rehabilitation program co-ordination, or quality improvement activities.</p><p><strong>(i)</strong> Is aware of and functions in accordance with legislation, policies and procedures affecting enrolled nursing practice. For example, able to discuss the implications of Acts and legislation governing practice.</p><p><strong>(j)</strong> Actively participates in team leadership and decision making. For example, participates in quality improvement activities or orientates new staff to local practices.</p><p><strong>82.17</strong> Portability of EN3 classification</p><p><strong>(a)</strong> An Enrolled Nurse classified at EN3 will be paid for all hours worked at the EN3 classification and continue to be employed at Level 3 across the public sector including in the event they change employer.</p><p><strong>(b)</strong> Evidence required to demonstrate EN3 to a new Employer will be any one of the following:</p><p><strong>(i)</strong> payslip;</p><p><strong>(ii)</strong> certificate of service; or</p><p><strong>(iii)</strong> letter of appointment.</p><p><strong>82.18</strong> Applications for advancement to EN3</p><p><strong>(a)</strong> Application principles</p><p><strong>(i)</strong> The process for applications for EN3 should ensure that applicants have equal opportunity to demonstrate their suitability.</p><p><strong>(ii)</strong> Applicants should have reasonable access to the same information relevant to the Level 3 criteria.</p><p><strong>(iii)</strong> No restrictions, other than the set eligibility requirements, are to apply.</p><p><strong>(iv)</strong> Potential applicants should be allowed reasonable time to prepare for the process.</p><p><strong>(b)</strong> Application process</p><p><strong>(i)</strong> Applications will be considered by the Employer twice per year. Applications will open for a period of 14 days.</p><p><strong>(ii)</strong> Written applications are to be made to the NUM (or equivalent position).</p><p><strong>(iii)</strong> The written application must address the criteria in this Agreement, including:</p><p><strong>(A)</strong> evidence of achievement of four out of ten of the Advanced Enrolled Nurse Level 3 criteria; and</p><p><strong>(B)</strong> either:</p><p>1) a minimum of four years post-registration experience as an Enrolled Nurse;</p><p>OR</p><p>2) a post-registration qualification (of at least 6 months or 200 hours duration), a component of which is relevant to the role;</p><p><strong>(iv)</strong> Interviews, if required:</p><p><strong>(A)</strong> will be held within 10 days of the closure of applications;</p><p><strong>(B)</strong> will be conducted at the local level by the NUM (or equivalent position) and may also include up to two other nursing staff such as an ANUM or Nurse Educator; and</p><p><strong>(C)</strong> must relate directly to the Advanced Enrolled Nurse Level 3 criteria, and the supporting evidence within the application.</p><p><strong>(v)</strong> The Enrolled Nurse will be notified in writing of the outcome within 7 days of the closing of applications, or where there is an interview, within 7 days after the interview.</p><p><strong>(vi)</strong> For successful applicants, re-grading will apply from the date of application and be payable from the next fortnightly pay period after notification of a successful application.</p><p><strong>(vii)</strong> If the application is unsuccessful, the Employer is to provide detailed written feedback aligned with the criteria, with a supportive development plan to be commenced to assist the Enrolled Nurse in any future application.</p>',102)])])}const g=t(r,[["render",s]]);export{h as __pageData,g as default};
